from dataclasses import dataclass, field
from typing import Literal

@dataclass
class StreamMetric:
    name: str
    baseline: float
    current: float
    target: float
    unit: str
    level: Literal["Business", "ValueStream", "AIIntervention", "Platform"]

    @property
    def pct_improvement(self) -> float:
        if self.baseline == 0:
            return 0.0
        return (self.baseline - self.current) / self.baseline * 100

    @property
    def rag(self) -> Literal["Green", "Amber", "Red"]:
        if self.baseline == self.target:
            return "Green"
        # Lower is better for cycle time / error rate metrics
        improvement_needed = abs(self.baseline - self.target)
        improvement_achieved = abs(self.baseline - self.current)
        ratio = improvement_achieved / improvement_needed if improvement_needed else 1.0
        if ratio >= 0.9:
            return "Green"
        if ratio >= 0.6:
            return "Amber"
        return "Red"

@dataclass
class ValueStreamDashboard:
    stream_name: str
    metrics: list[StreamMetric] = field(default_factory=list)

    def by_level(self, level: str) -> list[StreamMetric]:
        return [m for m in self.metrics if m.level == level]

    def summary(self) -> str:
        lines = [f"Dashboard: {self.stream_name}"]
        for level in ("Business", "ValueStream", "AIIntervention", "Platform"):
            level_metrics = self.by_level(level)
            if not level_metrics:
                continue
            lines.append(f"  [{level}]")
            for m in level_metrics:
                lines.append(
                    f"    {m.rag:5s} {m.name}: {m.current}{m.unit} "
                    f"(baseline={m.baseline}{m.unit}, target={m.target}{m.unit}, "
                    f"improvement={m.pct_improvement:.1f}%)"
                )
        return "\n".join(lines)

# Example: Insurance claims value stream
claims_dashboard = ValueStreamDashboard(
    stream_name="FNOL-to-Settlement",
    metrics=[
        StreamMetric("Settlement NPS", 32, 41, 50, "pts", "Business"),
        StreamMetric("Claims cost per case", 1200, 1050, 900, "USD", "Business"),
        StreamMetric("End-to-end cycle time", 12.0, 8.5, 7.0, "days", "ValueStream"),
        StreamMetric("FNOL error rate", 18.0, 9.0, 5.0, "pct", "ValueStream"),
        StreamMetric("AI handling rate (FNOL triage)", 0, 72, 80, "pct", "AIIntervention"),
        StreamMetric("Triage accuracy", 0, 91, 95, "pct", "AIIntervention"),
        StreamMetric("Human override rate", 0, 12, 8, "pct", "AIIntervention"),
        StreamMetric("Gateway uptime", 99.2, 99.6, 99.9, "pct", "Platform"),
    ],
)
print(claims_dashboard.summary())
